import{c as d,Z as a,Q as l,j as p,g as t,n as o,o as s,m as n,av as h}from"./chunks/framework.BPKcPtvA.js";const v=JSON.parse('{"title":"Arm Scoped autonomy on the dashboard","description":"Mint a Scoped session on the dashboard first — the install step asks for this key so your own LLM can trade without a deep-link.","frontmatter":{"title":"Arm Scoped autonomy on the dashboard","description":"Mint a Scoped session on the dashboard first — the install step asks for this key so your own LLM can trade without a deep-link."},"headers":[],"relativePath":"guide/mcp/arm-scoped.md","filePath":"guide/mcp/arm-scoped.md","lastUpdated":1780218602000}'),c={name:"guide/mcp/arm-scoped.md"};function u(m,e,g,y,k,b){const r=a("TaskMeta"),i=a("ExpectedResult");return l(),p("div",null,[e[1]||(e[1]=t("h1",{id:"arm-scoped-autonomy-on-the-dashboard",tabindex:"-1"},[o("Arm Scoped autonomy on the dashboard "),t("a",{class:"header-anchor",href:"#arm-scoped-autonomy-on-the-dashboard","aria-label":'Permalink to "Arm Scoped autonomy on the dashboard"'},"​")],-1)),s(r,{time:"~3 min",role:"Investor",needs:"A MuHaven passkey wallet"}),e[2]||(e[2]=n('<blockquote><p><strong>What you&#39;ll do:</strong> mint a <strong>Scoped session</strong> on the dashboard and copy its key. The MCP install step (<a href="/guide/mcp/install">M2</a>) asks for this key, and it&#39;s what lets your own LLM buy and sell <strong>without a dashboard deep-link</strong>.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Do this before you install</p><p>The autonomy tier is set on the <strong>dashboard only</strong> — the MCP server can&#39;t change it. Minting the Scoped session here first means <code>muhaven-broker setup</code> can consume the key when you install, so your LLM trades autonomously from the very first run. Without this, MCP buys/sells fall back to a dashboard deep-link you approve by hand.</p></div><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Sign in at <a href="https://muhaven.app" target="_blank" rel="noreferrer">muhaven.app</a> with your passkey (see <a href="/guide/investor/sign-in">I1 · Sign in</a>).</li><li>Go to <code>/agent/policy/transition</code>.</li><li>Pick the <strong><code>Scoped autonomy</code></strong> tier.</li><li>Set your <strong>per-trade cap</strong> (max mhUSDC per trade — defaults to $100) and a <strong>TTL</strong> (how long the session is valid).</li><li>Click <strong>Confirm transition</strong> and <strong>approve with your passkey</strong>.</li><li>A <strong>session-key reveal modal</strong> opens. Click <strong>Copy raw key</strong> (under <em>Raw private key · advanced</em>) — that&#39;s the value you&#39;ll paste when the installer prompts in <a href="/guide/mcp/install">M2</a>. Keep it on your clipboard (or in a password manager) for the next step.</li></ol><div class="warning custom-block"><p class="custom-block-title">Copy the raw key for the install prompt</p><p><code>muhaven-broker setup</code> asks you to <em>paste the session key</em> — it expects the <strong>raw <code>0x…</code> key</strong>, not the full command. Use <strong>Copy raw key</strong>. The modal&#39;s <em>Copy broker command</em> button (a one-paste <code>muhaven-broker update --session …</code>) is for rotating the key on a broker that&#39;s <strong>already running</strong> — handy later, but not what the first-time install prompt wants.</p></div><div class="info custom-block"><p class="custom-block-title">The key is minted on your device</p><p>The session key is generated <strong>client-side</strong> and never sent over the wire. The broker you install next gets time-boxed, capped signing rights — never your passkey.</p></div><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',8)),s(i,null,{default:h(()=>[...e[0]||(e[0]=[o(" A ",-1),t("strong",null,"live Scoped session",-1),o(" exists on your account (shown by the session banner + revoke zone on the policy page), and you've copied the ",-1),t("strong",null,"raw session key",-1),o(" ready to paste during install. ",-1)])]),_:1}),e[3]||(e[3]=n('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Reveal modal didn&#39;t mint a key</td><td>Cancel and reopen it; the key is generated locally, so retry on-device.</td></tr><tr><td>You closed the modal before copying</td><td>Re-opening the page mints a <strong>fresh</strong> key — just re-do the mint and copy the new raw key.</td></tr><tr><td>The cap or TTL won&#39;t accept your value</td><td>The per-trade cap must be at least <strong>$1 mhUSDC</strong>; pick a TTL from the offered options.</td></tr><tr><td>Want to lock it down later</td><td><strong>Revoke</strong> on the policy page, or ask your agent to <em>&quot;pause my agent&quot;</em> — both block every write instantly.</td></tr></tbody></table><p>→ Next: <a href="/guide/mcp/install">Install &amp; set up the MCP server</a></p>',3))])}const w=d(c,[["render",u]]);export{v as __pageData,w as default};
